 21→type headerGetter interface {
 22→	GetHeader(string) string
 23→}
 24→
 25→// DetectClientKind classifies the downstream client from request headers stored
 26→// in context. This keeps client-specific compatibility behavior isolated to the
 27→// Claude -> GPT compatibility path without mutating request payloads.
 28→func DetectClientKind(ctx context.Context) ClientKind {
 29→	if ctx == nil {
 30→		return ClientUnknown
 31→	}
 32→
 33→	getter, _ := ctx.Value("gin").(headerGetter)
 34→	if getter == nil {
 35→		return ClientUnknown
 36→	}
 37→
 38→	userAgent := strings.ToLower(strings.TrimSpace(getter.GetHeader("User-Agent")))
 39→	originator := strings.ToLower(strings.TrimSpace(getter.GetHeader("Originator")))
 40→
 41→	switch {
 42→	case strings.Contains(userAgent, "claude-vscode"):
 43→		return ClientClaudeVSCode
 44→	case strings.HasPrefix(userAgent, "claude-cli/"):
 45→		return ClientClaudeCLI
 46→	case strings.Contains(userAgent, "vscode/"), originator == "codex_exec":
 47→		return ClientCodexVSCode
 48→	default:
 49→		return ClientUnknown
 50→	}
 51→}
 52→
 53→// ShouldEmitSyntheticWebSearchTag limits synthetic Claude-style websearch text
 54→// blocks to the real Claude CLI path. VSCode/Codex clients have their own
 55→// rendering expectations and should not receive the same synthetic text.
 56→func ShouldEmitSyntheticWebSearchTag(kind ClientKind) bool {
 57→	return kind == ClientClaudeCLI
 58→}
 59→
 60→// ShouldSurfaceReasoningSummaryAsThinking controls whether Codex reasoning
 61→// summaries should be exposed as Claude "thinking" blocks. VSCode clients render
 62→// these summaries as if they were live thoughts, which is misleading because the
 63→// summaries usually arrive after the actual search work has already happened.
 64→func ShouldSurfaceReasoningSummaryAsThinking(kind ClientKind) bool {
 65→	switch kind {
 66→	case ClientClaudeCLI, ClientClaudeVSCode, ClientCodexVSCode:
 67→		return false
 68→	default:
 69→		return true
 70→	}
 71→}
