 73→// ShouldEmitVSCodeWebSearchProgress reports whether the client should receive a
 74→// compact progress hint tied to real web_search_call events instead of verbose
 75→// post-hoc reasoning summaries.
 76→func ShouldEmitVSCodeWebSearchProgress(kind ClientKind) bool {
 77→	switch kind {
 78→	case ClientClaudeVSCode, ClientCodexVSCode:
 79→		return true
